function solve(nums1: number[]): boolean {
    const n = nums1.length;
    if (n === 0) return true;

    // Precalculate the parity array p: p[i] = 0 if even, 1 if odd
    const p: number[] = nums1.map(x => x % 2);

    /**
     * Checks if it's possible to make all elements of nums2 have target parity K.
     * K=0 means all even, K=1 means all odd.
     * @param K The target parity (0 or 1).
     * @returns True if possible, false otherwise.
     */
    const checkParity = (K: 0 | 1): boolean => {
        for (let i = 0; i < n; i++) {
            const pi = p[i];

            // 1. Try Choice 1: nums2[i] = nums1[i]
            if (pi === K) {
                continue;
            }

            // 2. Choice 1 failed. Must use Choice 2: nums2[i] = nums1[i] - nums1[j] (j != i)
            // We need P(nums1[i]) XOR P(nums1[j]) = K
            // pi XOR pj = K
            // pj = K XOR pi
            const required_pj = K ^ pi;

            let foundJ = false;
            for (let j = 0; j < n; j++) {
                if (i === j) {
                    continue;
                }
                if (p[j] === required_pj) {
                    foundJ = true;
                    break;
                }
            }

            if (!foundJ) {
                // Cannot achieve target parity K for index i
                return false;
            }
        }
        // All indices satisfied target parity K
        return true;
    };

    // Check if all elements can be made Even (K=0) OR all elements can be made Odd (K=1)
    return checkParity(0) || checkParity(1);
}

